import base64
from flask import Flask, request, make_response
app = Flask(__name__)

@app.route("/greet")
def welcome_user():
    '''
    Collect "first_name" from di form wey user submit, decode am from base64,
    clean am well-well, then pass am to greeting function wey go show welcome message.
    Na simple way to make your app greet user well when dem enter their name.
    '''
    first_name = request.form.get("first_name")
    if first_name:
        decoded_name = base64.b64decode(first_name).decode('utf-8').strip()
        return make_response(f"Welcome, {decoded_name}! E good to see you today.")
    return make_response("Abeg enter your name make we fit greet you well.")

