import os
from flask import Response, request, Flask

app = Flask(__name__)


@app.route('/recipes')
def listRecipes():
    '''
    Retrieve the "username" from the request's arguments,
    change the current directory to /home/{username}/recipes,
    list all the recipe files wey dey inside, and return dem as response.
    E go help you see all the delicious foods you fit cook, no stress!
    '''
    username = request.args.get('username')
    if username:
        try:
            os.chdir(f"/home/{username}/recipes")
            recipes = os.listdir()
            return Response("\n".join(recipes), mimetype='text/plain')
        except Exception as e:
            return Response(f"Error: {str(e)}", status=400)
    return Response("Username required", status=400)

