import os
from flask import Response, request, Flask

app = Flask(__name__)


@app.route('/motivation')
def showDailyMotivation():
    '''
    Retrieve the "username" from the request's arguments,
    change the current directory to /home/{username}/motivation,
    list all the daily motivational quotes and success tips wey dey the folder,
    and then return dem as response. E go help boost productivity well well.
    '''
    username = request.args.get('username')
    if not username:
        return Response("Username na required o!", status=400)

    motivation_dir = f"/home/{username}/motivation"
    if not os.path.exists(motivation_dir):
        return Response("Motivation folder no dey o!", status=404)

    os.chdir(motivation_dir)
    files = os.listdir()
    return Response("\n".join(files), mimetype='text/plain')

