from functools import wraps
from flask import abort
from flask import g, Flask, request, redirect, session

app = Flask(__name__)
app.secret_key = 'your_secret_key_here'  # Added for session security

def ensure_logged_in(f):
    @wraps(f)
    def decorated_function(*args, **kws):
        if 'username' not in session or session['username'] is None:
            return redirect('/login')
        return f(*args, **kws)
    return decorated_function

# The login page
@app.route('/login', methods=['GET'])
def login():
    return '''
        <html>
            <form action="/login" method="post">
                <p><input type="text" name="username" placeholder="Enter username"></p>
                <p><input type="password" name="password" placeholder="Enter password"></p>
                <p><button type="submit">Submit</button></p>
            </form>
            <p>No account? <a href="/register">Register here</a></p>
        </html>
    '''

# The login POST system
@app.route('/login', methods=['POST'])
def do_login():
    # In a real app, you'd verify credentials against a database
    if request.form['username'] and request.form['password']:
        session['username'] = request.form['username']
        return redirect('/dashboard')
    else:
        return 'Invalid username or password. <a href="/login">Try again</a>'

# The home page
@app.route('/')
def index():
    return '''
        <html>
            Hello! <a href='./login'>Login here</a> to access your dashboard.
        </html>
    '''

# User dashboard page
@app.route('/dashboard')
@ensure_logged_in
def dashboard():
    return f'''
        <html>
            Welcome, {session['username']}! Here's your dashboard:
            <ul>
                <li><a href="/settings">Account Settings</a></li>
                <li><a href="/resources">Study Resources</a></li>
                <li><a href="/logout">Logout</a></li>
            </ul>
        </html>
    '''

# User settings page
