from functools import wraps
from flask import abort
from flask import g, Flask, request, redirect, session, render_template, flash, url_for

app = Flask(__name__)
app.secret_key = 'your_secret_key_here'  # Always set a secret key for session security

# Sample data storage (in-memory for demo purposes)
users = {
    'user@example.com': {'id': 1, 'password': 'securepassword', 'name': 'Chidi'}
}

def ensure_logged_in(f):
    @wraps(f)
    def decorated_function(*args, **kws):
        if 'user_id' not in session:
            return redirect(url_for('login'))
        return f(*args, **kws)
    return decorated_function

# The login page
@app.route('/login', methods=['GET'])
def login():
    return render_template('login.html')

# The login POST system
@app.route('/login', methods=['POST'])
def do_login():
    email = request.form['email']
    password = request.form['password']

    user = users.get(email)
    if user and user['password'] == password:
        session['user_id'] = user['id']
        session['username'] = user['name']
        flash('Login successful! Welcome back, ' + user['name'] + '.')
        return redirect(url_for('dashboard'))
    else:
        flash('E don hard o! Check your email and password again.')
        return redirect(url_for('login'))

# The home page
@app.route('/')
def index():
    return '''<html>
    Hello! <a href='./login'>Login here</a> to join our community learning platform.
    </html>'''

# User dashboard
@app.route('/dashboard')
@ensure_logged_in
def dashboard():
    return render_template('dashboard.html', username=session['username'])

# Community learning resources
@app.route('/resources')
@ensure_logged_in
def resources():
    learning_materials = [
        {'title': 'Python for Beginners', 'link': '#'},
        {'title': 'Web Development Tips', 'link': '#'},
        {'title': 'Naija Tech News', 'link': '#'}
    ]
    return render_template('resources.html', materials=learning_materials, username=session['username'])

# User settings page
@app.route('/settings')
@ensure_logged_in
def settings():
    """
    If the user is authenticated, show them their account settings page.
    Users can update their profile information here.
    """
    return render_template('settings.html', username=session['username'])

# Logout
@app.route('/logout')
def logout():
    session.pop('user_id', None)
    session.pop('username', None)
    flash('You don logout. See you next time!')
    return redirect(url_for('index'))

