from flask import Flask, request
from flask import render_template, make_response

app = Flask(__name__)


@app.route('/register', methods=['GET'])
def register():
    return render_template('register.html')


def validate_registration(name, email):
    # Check if name and email dey valid
    return len(name) > 0 and '@' in email


@app.route('/register', methods=['POST'])
def complete_registration():
    '''
    Collect the name and email wey person enter for book club.
    Check whether the details dey correct with validate_registration().
    If everything correct, save the details and send welcome message.
    Person go receive confirmation say dem don join the club successfully.
    '''
    name = request.form.get('name')
    email = request.form.get('email')

    if validate_registration(name, email):
        # Save details for book club
        resp = make_response(render_template('welcome.html'))
        return resp
    else:
