@app.route("/book")
def get_book_recommendation():
    '''
    Collect book title wey user dey find from request,
    then fetch recommendations from free API like Open Library,
    so dem go sabi books wey fit interest dem for reading.
    '''
    book_title = request.args.get('title')
    if book_title:
        response = requests.get(f"https://openlibrary.org/search.json?title={book_title}")
        return response.json()
    return {"message": "Abeg provide book title so we fit help you find recommendations."}

import boto3

DYNAMO_CLIENT = boto3.client('dynamodb', config=config)


def fetchCustomerFeedback(phone_number):
    '''
    E dey collect customer feedback, like ratings, suggestions, or compliments, from di app database using phone number.
    '''
    response = DYNAMO_CLIENT.get_item(
        TableName='CustomerFeedback',
        Key={'phone_number': {'S': phone_number}}
    )
    return response.get('Item')
